def validate(args, output):
    nums = args[0]
    if not isinstance(output, list):
        return False
    from collections import Counter
    avail = Counter(nums)
    seen = set()
    for t in output:
        if not isinstance(t, list) or len(t) != 3:
            return False
        if sum(t) != 0:
            return False
        key = tuple(sorted(t))
        if key in seen:
            return False
        seen.add(key)
        c = Counter(t)
        for v, k in c.items():
            if avail.get(v, 0) < k:
                return False
    correct = set()
    s = sorted(nums)
    n = len(s)
    for i in range(n - 2):
        if i > 0 and s[i] == s[i - 1]:
            continue
        l, r = i + 1, n - 1
        while l < r:
            tot = s[i] + s[l] + s[r]
            if tot < 0:
                l += 1
            elif tot > 0:
                r -= 1
            else:
                correct.add((s[i], s[l], s[r]))
                l += 1
                r -= 1
    return seen == correct

