function validate(args, output) {
    const nums = args[0];
    if (!Array.isArray(output)) return false;
    const avail = new Map();
    for (const v of nums) avail.set(v, (avail.get(v) || 0) + 1);
    const seen = new Set();
    for (const t of output) {
        if (!Array.isArray(t) || t.length !== 3) return false;
        if (t[0] + t[1] + t[2] !== 0) return false;
        const key = [...t].sort((a, b) => a - b).join(',');
        if (seen.has(key)) return false;
        seen.add(key);
        const c = new Map();
        for (const v of t) c.set(v, (c.get(v) || 0) + 1);
        for (const [v, k] of c) {
            if ((avail.get(v) || 0) < k) return false;
        }
    }
    const correct = new Set();
    const s = nums.slice().sort((a, b) => a - b);
    const n = s.length;
    for (let i = 0; i < n - 2; i++) {
        if (i > 0 && s[i] === s[i - 1]) continue;
        let l = i + 1, r = n - 1;
        while (l < r) {
            const tot = s[i] + s[l] + s[r];
            if (tot < 0) l++;
            else if (tot > 0) r--;
            else {
                correct.add([s[i], s[l], s[r]].join(','));
                l++; r--;
            }
        }
    }
    if (seen.size !== correct.size) return false;
    for (const k of seen) if (!correct.has(k)) return false;
    return true;
}

