class Solution:
    def threeSum(self, nums):
        n = len(nums)
        s = sorted(nums)
        found = set()
        for i in range(n):
            for j in range(i + 1, n):
                for k in range(j + 1, n):
                    if s[i] + s[j] + s[k] == 0:
                        found.add((s[i], s[j], s[k]))
        return [list(t) for t in sorted(found)]

