var threeSum = function(nums) {
    nums = nums.slice().sort((a, b) => a - b);
    const n = nums.length;
    const res = [];
    for (let i = 0; i < n - 2; i++) {
        if (i > 0 && nums[i] === nums[i - 1]) continue;
        let l = i + 1, r = n - 1;
        while (l < r) {
            const tot = nums[i] + nums[l] + nums[r];
            if (tot < 0) l++;
            else if (tot > 0) r--;
            else {
                res.push([nums[i], nums[l], nums[r]]);
                l++; r--;
                while (l < r && nums[l] === nums[l - 1]) l++;
                while (l < r && nums[r] === nums[r + 1]) r--;
            }
        }
    }
    return res;
